#include <stdio.h>
#include <stdlib.h>

int find(int* parent, int i) {
    if (parent[i] != i) {
        parent[i] = find(parent, parent[i]);
    }
    return parent[i];
}

void unionSet(int* parent, int* rank, int x, int y) {
    int xroot = find(parent, x);
    int yroot = find(parent, y);

    if (rank[xroot] < rank[yroot]) {
        parent[xroot] = yroot;
    } else if (rank[xroot] > rank[yroot]) {
        parent[yroot] = xroot;
    } else {
        parent[yroot] = xroot;
        rank[xroot]++;
    }
}

int minOperationsToConnectNetwork(int computerCount, int** cableConnections, int connectionCount) {
    int* parent = (int*)malloc(computerCount * sizeof(int));
    int* rank = (int*)malloc(computerCount * sizeof(int));

    for (int i = 0; i < computerCount; i++) {
        parent[i] = i;
        rank[i] = 0;
    }

    for (int i = 0; i < connectionCount; i++) {
        unionSet(parent, rank, cableConnections[i][0], cableConnections[i][1]);
    }

    int count = 0;
    for (int i = 0; i < computerCount; i++) {
        if (parent[i] == i) {
            count++;
        }
    }

    free(parent);
    free(rank);

    if (count == 1) {
        return 0;
    } else if (connectionCount >= computerCount - 1) {
        return count - 1;
    } else {
        return -1;
    }
}

int main() {
    int T;
    scanf("%d", &T);

    for (int t = 0; t < T; t++) {
        int computerCount;
        scanf("%d", &computerCount);

        int connectionCount;
        scanf("%d", &connectionCount);

        int** cableConnections = (int**)malloc(connectionCount * sizeof(int*));
        for (int i = 0; i < connectionCount; i++) {
            cableConnections[i] = (int*)malloc(2 * sizeof(int));
            scanf("%d %d", &cableConnections[i][0], &cableConnections[i][1]);
        }

        int result = minOperationsToConnectNetwork(computerCount, cableConnections, connectionCount);
        printf("%d\n", result);

        for (int i = 0; i < connectionCount; i++) {
            free(cableConnections[i]);
        }
        free(cableConnections);
    }

    return 0;
}

